mapper.insert:
INSERT INTO risk_analysis_record (
    user_id, city, factors, horizon_days, risk_level, risk_score, key_factor,
    confidence, prediction_json, trend_summary, explanation, suggestions,
    public_advice, report_content
)
VALUES (
    #{userId}, #{city}, #{factors}, #{horizonDays}, #{riskLevel}, #{riskScore}, #{keyFactor},
    #{confidence}, #{predictionJson}, #{trendSummary}, #{explanation}, #{suggestions},
    #{publicAdvice}, #{reportContent}
)

mapper.select:
SELECT COUNT(*)
FROM risk_analysis_record r
WHERE 1=1

    AND r.user_id = #{userId}


    AND r.city LIKE CONCAT('%', #{city}, '%')


    AND r.risk_level = #{riskLevel}

SELECT r.*, u.username AS create_user_name
FROM risk_analysis_record r
LEFT JOIN sys_user u ON r.user_id = u.id
WHERE 1=1

    AND r.user_id = #{userId}


    AND r.city LIKE CONCAT('%', #{city}, '%')


    AND r.risk_level = #{riskLevel}

ORDER BY r.create_time DESC
LIMIT #{offset}, #{size}
